import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useBus } from '../context/BusContext';
import { MagnifyingGlassIcon, MapPinIcon, CalendarIcon, ArrowRightIcon } from '@heroicons/react/24/outline';

const BusSearch = () => {
  const [searchData, setSearchData] = useState({
    source: '',
    destination: '',
    date: ''
  });
  const [errors, setErrors] = useState({});

  const { updateSearchCriteria } = useBus();
  const navigate = useNavigate();

  const tamilNaduCities = [
    'Chennai', 'Coimbatore', 'Madurai', 'Tiruchirappalli', 'Salem',
    'Erode', 'Tiruppur', 'Vellore', 'Thoothukudi', 'Dindigul',
    'Thanjavur', 'Ranipet', 'Sivakasi', 'Karur', 'Udhagamandalam',
    'Hosur', 'Nagercoil', 'Kanchipuram', 'Kumbakonam', 'Tirunelveli',
    'Cuddalore', 'Kanyakumari', 'Nagapattinam', 'Villupuram', 'Tiruvannamalai',
    'Pudukkottai', 'Ramanathapuram', 'Theni', 'Virudhunagar', 'Ariyalur',
    'Perambalur', 'Krishnagiri', 'Namakkal', 'Tirupathur', 'Chengalpattu'
  ];

  const validateForm = () => {
    const newErrors = {};

    if (!searchData.source.trim()) {
      newErrors.source = 'Source city is required';
    }

    if (!searchData.destination.trim()) {
      newErrors.destination = 'Destination city is required';
    }

    if (searchData.source === searchData.destination) {
      newErrors.destination = 'Source and destination cannot be the same';
    }

    if (!searchData.date) {
      newErrors.date = 'Travel date is required';
    } else {
      const selectedDate = new Date(searchData.date);
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      if (selectedDate < today) {
        newErrors.date = 'Travel date cannot be in the past';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (validateForm()) {
      updateSearchCriteria(searchData);
      navigate('/buses');
    }
  };

  const handleSwap = () => {
    setSearchData({
      ...searchData,
      source: searchData.destination,
      destination: searchData.source
    });
  };

  return (
    <div className="page-container page-shell bg-gradient-to-br from-orange-50 via-white to-red-50">
      <div className="page-content">
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-orange-600 to-red-600 mb-3">
            Find Your Bus in Tamil Nadu
          </h1>
          <p className="text-gray-600 text-lg">Search for buses between Tamil Nadu cities and book your journey</p>
        </div>

        <div className="max-w-4xl mx-auto">
          <div className="bg-white rounded-2xl shadow-2xl p-8 border border-orange-100">
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="form-group">
                  <label htmlFor="source" className="form-label text-orange-600 font-semibold">
                    From
                  </label>
                  <div className="relative">
                    <MapPinIcon className="absolute left-3 top-3 h-5 w-5 text-orange-400" />
                    <input
                      id="source"
                      type="text"
                      value={searchData.source}
                      onChange={(e) => setSearchData({ ...searchData, source: e.target.value })}
                      className={`form-input pl-10 border-orange-200 focus:border-orange-500 focus:ring-orange-500 ${errors.source ? 'border-red-500' : ''}`}
                      placeholder="Departure city"
                      list="source-cities"
                    />
                    <datalist id="source-cities">
                      {tamilNaduCities.map((city) => (
                        <option key={city} value={city} />
                      ))}
                    </datalist>
                  </div>
                  {errors.source && (
                    <p className="mt-1 text-sm text-red-600">{errors.source}</p>
                  )}
                </div>

                <div className="form-group">
                  <label htmlFor="destination" className="form-label text-orange-600 font-semibold">
                    To
                  </label>
                  <div className="relative">
                    <MapPinIcon className="absolute left-3 top-3 h-5 w-5 text-orange-400" />
                    <input
                      id="destination"
                      type="text"
                      value={searchData.destination}
                      onChange={(e) => setSearchData({ ...searchData, destination: e.target.value })}
                      className={`form-input pl-10 border-orange-200 focus:border-orange-500 focus:ring-orange-500 ${errors.destination ? 'border-red-500' : ''}`}
                      placeholder="Arrival city"
                      list="destination-cities"
                    />
                    <datalist id="destination-cities">
                      {tamilNaduCities.map((city) => (
                        <option key={city} value={city} />
                      ))}
                    </datalist>
                  </div>
                  {errors.destination && (
                    <p className="mt-1 text-sm text-red-600">{errors.destination}</p>
                  )}
                </div>
              </div>

              <div className="form-group">
                <label htmlFor="date" className="form-label text-orange-600 font-semibold">
                  Travel Date
                </label>
                <div className="relative">
                  <CalendarIcon className="absolute left-3 top-3 h-5 w-5 text-orange-400" />
                  <input
                    id="date"
                    type="date"
                    value={searchData.date}
                    onChange={(e) => setSearchData({ ...searchData, date: e.target.value })}
                    min={new Date().toISOString().split('T')[0]}
                    className={`form-input pl-10 border-orange-200 focus:border-orange-500 focus:ring-orange-500 ${errors.date ? 'border-red-500' : ''}`}
                  />
                </div>
                {errors.date && (
                  <p className="mt-1 text-sm text-red-600">{errors.date}</p>
                )}
              </div>

              <div className="pt-4">
                <button
                  type="submit"
                  className="btn btn-primary btn-full bg-gradient-to-r from-orange-600 to-red-600 hover:from-orange-700 hover:to-red-700 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300"
                >
                  <MagnifyingGlassIcon className="h-5 w-5 mr-2" />
                  Search Buses
                </button>
              </div>
            </form>
          </div>

          {/* Popular Routes */}
          <div className="mt-8 bg-white rounded-2xl shadow-xl p-6 border border-orange-100">
            <div className="card-header">
              <h2 className="card-title text-2xl font-bold text-orange-600 mb-4">Popular Routes in Tamil Nadu</h2>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {[
                { from: 'Chennai', to: 'Coimbatore' },
                { from: 'Chennai', to: 'Madurai' },
                { from: 'Chennai', to: 'Tiruchirappalli' },
                { from: 'Coimbatore', to: 'Madurai' },
                { from: 'Salem', to: 'Chennai' },
                { from: 'Tiruppur', to: 'Chennai' }
              ].map((route, index) => (
                <button
                  key={index}
                  onClick={() => setSearchData({
                    ...searchData,
                    source: route.from,
                    destination: route.to
                  })}
                  className="flex items-center justify-between p-4 border border-orange-200 rounded-xl hover:bg-gradient-to-r hover:from-orange-50 hover:to-red-50 hover:border-orange-300 transition-all duration-300 group"
                >
                  <div className="flex items-center">
                    <MapPinIcon className="h-5 w-5 text-orange-500 mr-3 group-hover:scale-110 transition-transform" />
                    <span className="text-sm font-semibold text-gray-800 group-hover:text-orange-600 transition-colors">
                      {route.from} → {route.to}
                    </span>
                  </div>
                  <ArrowRightIcon className="h-4 w-4 text-orange-400 group-hover:translate-x-1 transition-transform" />
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BusSearch;
